import{_ as e,o as i,c as a,a2 as n}from"./chunks/framework.BflysNKA.js";const g=JSON.parse('{"title":"Windows 环境准备","description":"","frontmatter":{},"headers":[],"relativePath":"beginner/windows-env.md","filePath":"beginner/windows-env.md","lastUpdated":1780486201000}'),l={name:"beginner/windows-env.md"};function t(p,s,r,o,d,h){return i(),a("div",null,[...s[0]||(s[0]=[n(`<h1 id="windows-环境准备" tabindex="-1">Windows 环境准备 <a class="header-anchor" href="#windows-环境准备" aria-label="Permalink to &quot;Windows 环境准备&quot;">​</a></h1><p>安装 Claude Code、Codex 等命令行工具之前，需要先准备好 PowerShell 执行策略、Git 和 Node.js。</p><div class="tip custom-block"><p class="custom-block-title">只用 Cherry Studio？</p><p>Cherry Studio 是桌面客户端，不需要命令行环境。直接去 <a href="/beginner/windows-cherry-studio">Cherry Studio 接入</a>。</p></div><h2 id="第-1-步-打开-powershell" tabindex="-1">第 1 步：打开 PowerShell <a class="header-anchor" href="#第-1-步-打开-powershell" aria-label="Permalink to &quot;第 1 步：打开 PowerShell&quot;">​</a></h2><p>按 <code>Win</code> 键，搜索 <code>PowerShell</code>，<strong>右键选择「以管理员身份运行」</strong>。</p><p>如果弹出「是否允许此应用对你的设备进行更改」，选 <strong>是</strong>。</p><p>你会看到一个蓝色（或黑色）的终端窗口，光标在等你输入命令。后面所有命令都在这个窗口里执行。</p><h2 id="第-2-步-修改-powershell-执行策略" tabindex="-1">第 2 步：修改 PowerShell 执行策略 <a class="header-anchor" href="#第-2-步-修改-powershell-执行策略" aria-label="Permalink to &quot;第 2 步：修改 PowerShell 执行策略&quot;">​</a></h2><p>Windows 默认禁止执行脚本。Claude Code 和 npm 工具需要执行 <code>.ps1</code> 脚本，不改这个策略会报 <code>running scripts is disabled</code>。</p><p>在 PowerShell 里输入（整行复制粘贴后按回车）：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">Set-ExecutionPolicy</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">Scope CurrentUser </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">ExecutionPolicy RemoteSigned</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>系统会问你是否确认，输入 <code>Y</code> 按回车。</p><p>验证是否生效：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">Get-ExecutionPolicy</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">List</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>在输出的表格中，<strong>CurrentUser</strong> 那一行应该显示 <code>RemoteSigned</code>。如果还是 <code>Undefined</code> 或 <code>Restricted</code>，说明没有成功，检查是否用了管理员权限运行。</p><h2 id="第-3-步-安装-git" tabindex="-1">第 3 步：安装 Git <a class="header-anchor" href="#第-3-步-安装-git" aria-label="Permalink to &quot;第 3 步：安装 Git&quot;">​</a></h2><p>Git 是代码版本管理工具，Claude Code 读取项目信息时需要用到。</p><p><strong>方式一（推荐）：WinGet 安装</strong></p><p>在 PowerShell 里执行：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">winget install </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">id Git.Git </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">e </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">source winget</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>安装完成后，<strong>关闭 PowerShell 窗口</strong>，再重新打开一个新的。</p><p><strong>方式二：手动下载安装</strong></p><p>从 <a href="https://git-scm.com/download/win" target="_blank" rel="noreferrer">git-scm.com</a> 下载安装包。安装过程中，所有选项保持默认即可。安装完成后同样需要重开终端。</p><p>验证 Git 是否安装成功：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">git </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>应该显示 <code>git version 2.xx.x</code>。如果提示 <code>git</code> 不是命令，说明 PATH 没有配对，重新安装并勾选 <code>Add Git to PATH</code>。</p><h2 id="第-4-步-安装-node-js" tabindex="-1">第 4 步：安装 Node.js <a class="header-anchor" href="#第-4-步-安装-node-js" aria-label="Permalink to &quot;第 4 步：安装 Node.js&quot;">​</a></h2><p>Node.js 是 JavaScript 运行环境，Claude Code（npm 方式安装）和 Codex 都需要它。</p><div class="tip custom-block"><p class="custom-block-title">不确定要不要装？</p><p>如果你用 Claude Code 的<strong>官方脚本安装</strong>（<code>irm https://claude.ai/install.ps1 | iex</code>），可以跳过 Node.js。但如果后面还想用 Codex、Gemini CLI 或其他 npm 工具，建议现在就装好。</p></div><p>从以下任一地址下载 <strong>LTS（长期支持）版本</strong>：</p><ul><li><a href="https://nodejs.cn/download" target="_blank" rel="noreferrer">Node.js 中文站</a> — 国内下载快</li><li><a href="https://nodejs.org/en/download" target="_blank" rel="noreferrer">Node.js 官网</a></li></ul><p>选 <strong>Windows 安装包 (.msi) 64 位</strong>。安装时注意：</p><ul><li><strong>保留「Add to PATH」选项</strong>（默认勾选，不要取消）</li><li>其他选项保持默认</li></ul><p>安装完成后，<strong>关闭 PowerShell 窗口</strong>，重新打开一个新的。验证：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">node </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">v</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">npm </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>应该分别显示版本号（如 <code>v22.x.x</code> 和 <code>11.x.x</code>）。如果提示命令不存在，说明 PATH 没有配对，重新安装。</p><h2 id="第-5-步-设置-npm-国内镜像-推荐" tabindex="-1">第 5 步：设置 npm 国内镜像（推荐） <a class="header-anchor" href="#第-5-步-设置-npm-国内镜像-推荐" aria-label="Permalink to &quot;第 5 步：设置 npm 国内镜像（推荐）&quot;">​</a></h2><p>npm 默认从国外下载，国内网络可能很慢。切换到国内镜像：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">npm config set registry https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">//</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">registry.npmmirror.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>验证镜像是否设置成功：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">npm config get registry</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>应该输出 <code>https://registry.npmmirror.com/</code>。</p><h2 id="最终检查" tabindex="-1">最终检查 <a class="header-anchor" href="#最终检查" aria-label="Permalink to &quot;最终检查&quot;">​</a></h2><p>在一个新的 PowerShell 窗口里执行以下三条命令：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">git </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">version</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">node </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">v</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">npm </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>三条都有版本号输出，环境就准备好了。接下来选一个工具开始配置：</p><ul><li>→ <a href="/beginner/windows-claude-code">Windows 接入 Claude Code</a></li><li>→ <a href="/beginner/windows-codex">Windows 接入 Codex</a></li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong><code>winget</code> 命令不存在？</strong></p><p><code>winget</code> 是 Windows 自带的包管理工具，Windows 10 1709+ 和 Windows 11 都有。如果没有，去 Microsoft Store 搜索「App Installer」安装。或者直接用手动下载安装包的方式。</p><p><strong>安装了但命令不存在？</strong></p><p>安装完 Git 或 Node.js 后，必须<strong>关闭当前终端窗口，重新打开一个新的</strong>。环境变量只在新窗口中生效。</p><p><strong>npm 安装包一直超时？</strong></p><p>先设置国内镜像（第 5 步），如果还是不行，检查网络是否有代理。公司网络可能需要配置代理：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">npm config set proxy http:</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">代理地址:端口</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">npm config set https</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">proxy http:</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">代理地址:端口</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div>`,55)])])}const k=e(l,[["render",t]]);export{g as __pageData,k as default};
